module RefModule(
   input         clock, reset, load,
   input [15:0]  loadValue,
   output [15:0] count,
   output        flag);reg [15:0]    obf_countReg = 16'b0;
   wire          flagWire;

   assign flag = flagWire;
   assign count = obf_countReg;

   always @ (posedge clock) begin 
      if (reset)
         obf_countReg <= 16'b0;
      else if (load)
         obf_countReg <= loadValue;
      else if (obf_countReg == {16{1'b1}})
         obf_countReg <= 16'b0;
      else
         obf_countReg <= obf_countReg + 1;
   end

   assign flagWire = (obf_countReg == {16{1'b1}});

endmodule
